CREATE OR REPLACE VIEW `vplantcurrentgrowthmedium` AS select `r`.`plantId` AS `plantId`,`r`.`newGrowthMediumId` AS `newGrowthMediumId`,`gm`.`name` AS `growthMediumName`,`r`.`potSize` AS `potSize`,`r`.`repottingNotes` AS `repottingNotes`,`r`.`repotDate` AS `repotDate` from ((select `repotting`.`repottingId` AS `repottingId`,`repotting`.`plantId` AS `plantId`,`repotting`.`newGrowthMediumId` AS `newGrowthMediumId`,`repotting`.`potSize` AS `potSize`,`repotting`.`repottingNotes` AS `repottingNotes`,`repotting`.`repotDate` AS `repotDate`,row_number() OVER (PARTITION BY `repotting`.`plantId` ORDER BY `repotting`.`repotDate` desc,`repotting`.`repottingId` desc )  AS `rn` from `repotting` where (`repotting`.`isActive` = 1)) `r` left join `growthmedium` `gm` on((`gm`.`growthMediumId` = `r`.`newGrowthMediumId`))) where (`r`.`rn` = 1);

